### Process Next.js Authentication Callback URL with Route Handlers

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/backend-for-frontend.mdx

This Route Handler serves as a callback URL for third-party authentication flows. It retrieves a session token and a redirect URL from query parameters, securely sets the session token as an HTTP-only cookie, and then redirects the user to the specified URL to complete the authentication process.

```ts
import { type NextRequest, NextResponse } from 'next/server'

export async function GET(request: NextRequest) {
  const token = request.nextUrl.searchParams.get('session_token')
  const redirectUrl = request.nextUrl.searchParams.get('redirect_url')

  const response = NextResponse.redirect(new URL(redirectUrl, request.url))

  response.cookies.set({
    value: token,
    name: '_token',
    path: '/',
    secure: true,
    httpOnly: true,
    expires: undefined, // session cookie
  })

  return response
}
```

